@* Displays a single task with move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2 d-flex gap-1">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveLeft.InvokeAsync(Task)">
                    &larr; Move Left
                </button>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="() => OnMoveRight.InvokeAsync(Task)">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form to create a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card border-primary">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title"
                       @bind="title" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                       @bind="assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="dueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@saving">
                    @(saving ? "Saving..." : "Save")
                </button>
                <button class="btn btn-secondary btn-sm" @onclick="Hide" disabled="@saving">Cancel</button>
            </div>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool saving;

    private void Show() => IsVisible = true;

    private void Hide()
    {
        IsVisible = false;
        ResetForm();
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        saving = true;
        try
        {
            await OnTaskCreated.InvokeAsync(
                new TaskItem(0, title.Trim(), assignee.Trim(), priority, dueDate, Status));
            Hide();
        }
        finally
        {
            saving = false;
        }
    }
}

@* A single Kanban column with header, task cards, and add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="OnMoveLeft"
                          OnMoveRight="OnMoveRight" />
            }
            <AddTaskForm Status="@Status" OnTaskCreated="OnTaskCreated" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
}

@* Search bar for filtering tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           @bind="SearchText"
           @bind:event="oninput"
           @bind:after="NotifyChanged" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private Task NotifyChanged() => SearchTextChanged.InvokeAsync(SearchText);
}

@page "/board"
@using sv_f2c165c6a6b94058b621e59644d5b75b.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Total="tasks.Count"
                TodoCount="todoTasks.Count"
                InProgressCount="inProgressTasks.Count"
                DoneCount="doneTasks.Count"
                OverdueCount="tasks.Count(t => t.DueDate < DateTime.Today)" />

    <TaskSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Status="To Do"
                      Tasks="FilteredTodo"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRight="t => MoveTask(t, \"In Progress\")"
                      OnTaskCreated="CreateTask" />

        <KanbanColumn ColumnName="In Progress"
                      Status="In Progress"
                      Tasks="FilteredInProgress"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="t => MoveTask(t, \"To Do\")"
                      OnMoveRight="t => MoveTask(t, \"Done\")"
                      OnTaskCreated="CreateTask" />

        <KanbanColumn ColumnName="Done"
                      Status="Done"
                      Tasks="FilteredDone"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeft="t => MoveTask(t, \"In Progress\")"
                      OnTaskCreated="CreateTask" />
    </div>
}

@code {
    private List<TaskItem> tasks = new();
    private bool loading = true;
    private string? errorMessage;
    private string searchText = "";

    private List<TaskItem> todoTasks => tasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => tasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => tasks.Where(t => t.Status == "Done").ToList();

    private List<TaskItem> FilteredTodo => ApplySearch(todoTasks);
    private List<TaskItem> FilteredInProgress => ApplySearch(inProgressTasks);
    private List<TaskItem> FilteredDone => ApplySearch(doneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> source)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return source;
        return source.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = tasks.IndexOf(task);
            if (index >= 0)
            {
                tasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task CreateTask(TaskItem placeholder)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                placeholder.Title, placeholder.Assignee, placeholder.Priority, placeholder.DueDate);
            tasks.Add(created with { Status = placeholder.Status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

