{"path": "/tmp/sv-f2c165c6a6b94058b621e59644d5b75b/Components/Pages/Board.razor", "file_text": "@page "/board"
@using sv_f2c165c6a6b94058b621e59644d5b75b.Components.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Total="tasks.Count"
                TodoCount="todoTasks.Count"
                InProgressCount="inProgressTasks.Count"
                DoneCount="doneTasks.Count"
                OverdueCount="tasks.Count(t => t.DueDate < DateTime.Today)" />

    <TaskSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Status="To Do"
                      Tasks="FilteredTodo"
                      CanMoveLeft="false"
                      CanMoveRight="true"
                      OnMoveRight="t => MoveTask(t, \"In Progress\")"
                      OnTaskCreated="CreateTask" />

        <KanbanColumn ColumnName="In Progress"
                      Status="In Progress"
                      Tasks="FilteredInProgress"
                      CanMoveLeft="true"
                      CanMoveRight="true"
                      OnMoveLeft="t => MoveTask(t, \"To Do\")"
                      OnMoveRight="t => MoveTask(t, \"Done\")"
                      OnTaskCreated="CreateTask" />

        <KanbanColumn ColumnName="Done"
                      Status="Done"
                      Tasks="FilteredDone"
                      CanMoveLeft="true"
                      CanMoveRight="false"
                      OnMoveLeft="t => MoveTask(t, \"In Progress\")"
                      OnTaskCreated="CreateTask" />
    </div>
}

@code {
    private List<TaskItem> tasks = new();
    private bool loading = true;
    private string? errorMessage;
    private string searchText = "";

    private List<TaskItem> todoTasks => tasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => tasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => tasks.Where(t => t.Status == "Done").ToList();

    private List<TaskItem> FilteredTodo => ApplySearch(todoTasks);
    private List<TaskItem> FilteredInProgress => ApplySearch(inProgressTasks);
    private List<TaskItem> FilteredDone => ApplySearch(doneTasks);

    private List<TaskItem> ApplySearch(List<TaskItem> source)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return source;
        return source.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;
        try
        {
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = tasks.IndexOf(task);
            if (index >= 0)
            {
                tasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task CreateTask(TaskItem placeholder)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(
                placeholder.Title, placeholder.Assignee, placeholder.Priority, placeholder.DueDate);
            tasks.Add(created with { Status = placeholder.Status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}
"}

